+// Math.min()            # Math.max()
+// ----------------------------------
+// vucomxs[h/s/d]        #
+// ja   -> b             # a
+// je   -> a | b         # a & b
+// jp   -> NaN           # NaN
+// jb   -> a             # b
+static void emit_fp_min_max_avx10_2(MacroAssembler* masm, XMMRegister dst,
+                                    XMMRegister a, XMMRegister b,
+                                    Register rt, bool min,
+                                    enum FP_PREC pt) {
+  Label nan, equal, above, done;
+
+  emit_fp_ucom_avx10_2(masm, pt, a, b);
+
+  if (dst->encoding() != (min ? b : a)->encoding()) {
+    __ jccb(Assembler::above, above); // CF=0 & ZF=0
+  } else {
+    __ jccb(Assembler::above, done);
+  }
+  __ jccb(Assembler::equal, equal); // ZF=1
+  __ jccb(Assembler::parity, nan); // PF=1
+
+  // below
+  movfp(masm, pt, dst, min ? a : b, rt);
+  __ jmp(done);
+
+  __ bind(above);
+  movfp(masm, pt, dst, min ? b : a, rt);
+  __ jmp(done);
+
+  __ bind(equal);
+  emit_fp_equal(masm, dst, a, b, min);
+  __ jmp(done);
+
+  __ bind(nan);
+  emit_fp_nan(masm, pt, dst, rt);
+
+  __ bind(done);
+}
